# Module providing mathematical utility functions and classes

class Calculator:
    precision: int

    def __init__(self, precision: int):
        self.precision = precision

    def round_result(self, value: float) -> float:
        multiplier: float = 10.0 ** self.precision
        return float(int(value * multiplier)) // 1.0 * (1.0 / multiplier)

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    result: int = 1
    i: int = 2
    while i <= n:
        result *= i
        i += 1
    return result

def is_prime(n: int) -> bool:
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    i: int = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

def gcd(a: int, b: int) -> int:
    while b != 0:
        temp: int = b
        b = a % b
        a = temp
    return a

