# Module providing string manipulation utilities

def reverse_string(s: str) -> str:
    chars: list[str] = [c for c in s]
    result: str = ""
    i: int = len(chars) - 1
    while i >= 0:
        result = f"{result}{chars[i]}"
        i -= 1
    return result

def count_vowels(text: str) -> int:
    vowels: str = "aeiouAEIOU"
    count: int = 0
    for char in text:
        if char in vowels:
            count += 1
    return count

class TextFormatter:
    prefix: str
    suffix: str

    def __init__(self, prefix: str, suffix: str):
        self.prefix = prefix
        self.suffix = suffix

    def format(self, text: str) -> str:
        return f"{self.prefix}{text}{self.suffix}"
